# Pre-Deployment Validation Script# Runs all checks before deploymentparam(    [switch]$Quick)$ErrorActionPreference = "Stop"$passed = 0$failed = 0function Test-Step {    param($Name, $ScriptBlock)        Write-Host "`n" -NoNewline    Write-Host "▶ $Name..." -ForegroundColor Cyan -NoNewline    try {        & $ScriptBlock        Write-Host " ✅" -ForegroundColor Green        $script:passed++        return $true    } catch {        Write-Host " ❌" -ForegroundColor Red        Write-Host "  Error: $_" -ForegroundColor Red        $script:failed++        return $false    }}Write-Host "🔍 WAssistant Pre-Deployment Validation" -ForegroundColor CyanWrite-Host "========================================" -ForegroundColor Cyan# 1. Flutter DoctorTest-Step "Flutter doctor" {    $output = flutter doctor    if ($output -match "No issues found") {        return    }    if ($output -notmatch "\[!\]|\[✗\]") {        return    }    throw "Flutter doctor found issues"}# 2. Code AnalysisTest-Step "Flutter analyze" {    $output = flutter analyze 2>&1    if ($output -match "(\d+) issues found") {        $count = [int]$matches[1]        if ($count -gt 10) {            throw "$count issues found - max 10 allowed"        }    }}# 3. Unit Testsif (-not $Quick) {    Test-Step "Unit tests" {        $output = flutter test test/unit --no-pub 2>&1        if ($LASTEXITCODE -ne 0) {            throw "Tests failed"        }        if ($output -match "All tests passed") {            return        }        throw "Test validation failed"    }}# 4. Code FormattingTest-Step "Code formatting" {    $output = dart format --output=none --set-exit-if-changed lib test 2>&1    # Exit code 0 = no changes needed, 1 = changes made    if ($LASTEXITCODE -le 1) {        return    }    throw "Formatting check failed"}# 5. Localization CheckTest-Step "Localization completeness" {    $arbFiles = Get-ChildItem "lib/l10n/*.arb"    $keyCounts = @()    foreach ($file in $arbFiles) {        $content = Get-Content $file.FullName | ConvertFrom-Json        $keys = ($content.PSObject.Properties | Where-Object { $_.Name -notlike '@*' }).Count        $keyCounts += $keys    }        $unique = $keyCounts | Select-Object -Unique    if ($unique.Count -ne 1) {        throw "Localization key mismatch: $($keyCounts -join ', ')"    }}# 6. Version CheckTest-Step "Version format" {    $pubspec = Get-Content "pubspec.yaml" | Out-String    if ($pubspec -match "version:\s+(\d+\.\d+\.\d+)") {        return    }    throw "Invalid version format in pubspec.yaml"}# 7. Environment FileTest-Step "Environment configuration" {    if (-not (Test-Path ".env")) {        throw ".env file not found"    }        $env = Get-Content ".env"    $required = @('ADMOB_APP_ID_ANDROID', 'ADMOB_APP_ID_IOS')    foreach ($key in $required) {        if ($env -notmatch "$key=") {            throw "Missing $key in .env"        }    }}# 8. Android Keystore (if building for Android)if (Test-Path "android/key.properties") {    Test-Step "Android signing" {        if (-not (Test-Path "android/app/keystore.jks")) {            throw "keystore.jks not found"        }    }} else {    Write-Host "`n" -NoNewline    Write-Host "▶ Android signing..." -ForegroundColor Cyan -NoNewline    Write-Host " ⚠️  Not configured" -ForegroundColor Yellow    Write-Host "  Run: .\scripts\generate_keystore.ps1" -ForegroundColor Gray}# SummaryWrite-Host ""Write-Host "========================================" -ForegroundColor CyanWrite-Host "Results: $passed passed" -NoNewline -ForegroundColor Greenif ($failed -gt 0) {    Write-Host ", $failed failed" -ForegroundColor Red    Write-Host ""    Write-Host "❌ Validation failed! Fix issues before deploying." -ForegroundColor Red    exit 1} else {    Write-Host ""    Write-Host ""    Write-Host "✅ All checks passed! Ready to deploy." -ForegroundColor Green        Write-Host ""    Write-Host "Next steps:" -ForegroundColor Yellow    Write-Host '  Web:     .\scripts\deploy_web.ps1' -ForegroundColor Gray    Write-Host '  Android: .\scripts\build_android.ps1' -ForegroundColor Gray    Write-Host '  iOS:     See DEPLOYMENT_GUIDE.md' -ForegroundColor Gray    exit 0}
